return $input.all().slice(0, 10);

const items_out = [];

// 1. Only process the top 5 articles to stay safely inside Groq's free rate limits
const limitedItems = items.slice(0, 5);

// Helper function to force n8n to pause between API calls
const delay = ms => new Promise(resolve => setTimeout(resolve, ms));

for (const item of limitedItems) {
  const title = (item.json.title || "").replace(/"/g,"").replace(/'/g,"").replace(/\n/g," ");

  try {
    // 2. Make the live AI request to Groq
    const response = await this.helpers.httpRequest({
      method: "POST",
      url: "https://api.groq.com/openai/v1/chat/completions",
      headers: {
        "Authorization": "Bearer YOUR_API_KEY",
        "Content-Type": "application/json"
      },
      body: {
        model: "llama-3.3-70b-versatile",
        max_tokens: 300,
        messages: [{
          role: "user",
          content: "Analyze this tech headline for stock impact. Return JSON only with keys: sentiment (Positive/Negative/Neutral), company (or null), reason (1 sentence), confidence (0.0-1.0). Headline: " + title
        }]
      },
      json: true
    });

    items_out.push({
      json: {
        title: item.json.title,
        link: item.json.link,
        pubDate: item.json.pubDate,
        ai_result: response.choices[0].message.content
      }
    });

    // 3. Pause for 2 seconds before analyzing the next headline to prevent 429 errors
    await delay(2000);

  } catch (error) {
    console.error("Groq API error on headline: " + title, error);

    // FALLBACK: If Groq hits a limit anyway, pass the article through blank 
    // so your pipeline keeps moving forward without breaking!
    items_out.push({
      json: {
        title: item.json.title,
        link: item.json.link,
        pubDate: item.json.pubDate,
        ai_result: '{"sentiment": "Neutral", "company": "Unknown", "reason": "AI Analysis skipped due to rate limit."}'
      }
    });
  }
}

return items_out;

// Loop through all incoming articles from the feed
for (let item of $input.all()) {
    // Read the headline title and lowercase it so search isn't case-sensitive
    let titleText = (item.json.title || '').toLowerCase();

    // Scan the headline text for company keywords and tag them cleanly
    if (titleText.includes('apple') || titleText.includes('iphone') || titleText.includes('macbook')) {
        item.json.Company = 'Apple';
    } else if (titleText.includes('microsoft') || titleText.includes('windows')) {
        item.json.Company = 'Microsoft';
    } else if (titleText.includes('meta') || titleText.includes('facebook') || titleText.includes('instagram')) {
        item.json.Company = 'Meta';
    } else if (titleText.includes('google') || titleText.includes('alphabet') || titleText.includes('youtube')) {
        item.json.Company = 'Google';
    } else if (titleText.includes('nvidia') || titleText.includes('gpu')) {
        item.json.Company = 'Nvidia';
    } else if (titleText.includes('amazon')) {
        item.json.Company = 'Amazon';
    } else if (titleText.includes('tesla') || titleText.includes('elon musk')) {
        item.json.Company = 'Tesla';
    } else {
        // Fallback name if it's a general tech article
        item.json.Company = 'Tech Giant'; 
    }
}

// Pass the updated items with clean company names down the line
return $input.all();

const allArticles = items.map(item => `
  <tr>
    <td><a href="${item.json.link}">${item.json.title}</a></td>
    <td style="color:${item.json.sentiment === 'Positive' ? 'green' : item.json.sentiment === 'Negative' ? 'red' : 'gray'}">${item.json.sentiment}</td>
    <td>${item.json.company}</td>
    <td>${item.json.reason}</td>
    <td>${item.json.confidence}</td>
  </tr>
`).join('');

return [{
  json: {
    emailBody: `
      <h2>📰 Daily Tech News Sentiment Report</h2>
      <table border="1" cellpadding="8" style="border-collapse:collapse;width:100%">
        <tr style="background:#4A90D9;color:white">
          <th>Title</th><th>Sentiment</th><th>Company</th><th>Reason</th><th>Confidence</th>
        </tr>
        ${allArticles}
      </table>
    `,
    totalArticles: items.length
  }
}];
